import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { getSaleById, updateSale } from "../../api/saleApi";

export default function EditPayment() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);

  const [form, setForm] = useState({
    price: "",
    payment_status: "pending",
  });

  useEffect(() => {
    const load = async () => {
      try {
        const res = await getSaleById(id);
        const s = res.data;

        setForm({
          price: s.price ?? "",
          payment_status: s.payment_status || "pending",
        });
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load sale");
        navigate("/sales");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [id, navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((p) => ({ ...p, [name]: name === "price" ? Number(value) : value }));
  };

  const submit = async (e) => {
    e.preventDefault();
    try {
      await updateSale(id, form);
      alert("Updated!");
      navigate("/sales");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

  if (loading) return <p style={{ padding: 20 }}>Loading...</p>;

  return (
    <div style={{ padding: 20, maxWidth: 520 }}>
      <h2>Edit Payment</h2>

      <form onSubmit={submit}>
        <label>Price</label><br />
        <input
          name="price"
          type="number"
          min="0"
          value={form.price}
          onChange={handleChange}
          style={{ width: "100%", padding: 10 }}
          required
        />

        <br /><br />

        <label>Payment Status</label><br />
        <select
          name="payment_status"
          value={form.payment_status}
          onChange={handleChange}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="pending">Pending</option>
          <option value="partial">Partial</option>
          <option value="completed">Completed</option>
        </select>

        <br /><br />

        <button style={{ padding: "10px 14px" }}>Save</button>
      </form>
    </div>
  );
}
